import { Component, Host, Prop, h } from '@stencil/core';

@Component({
  tag: 'mx-title-content',
  styleUrl: 'mx-title-content.css',
  shadow: false
})
export class MxTitleContent {
  /** Sets the content of the title. */
  @Prop() readonly content: string;

  render() {
    return (
      <Host>
        <div>
          <kds-text textClass='pl-16 heading-m font-medium'>{this.content}</kds-text>
        </div>
        <slot></slot>
      </Host>
    );
  }
}
